// 象棋音效管理模块
// 使用内嵌 Base64 WAV 数据，无需外部文件

const SOUNDS = {
  move: 'data:audio/wav;base64,',
  capture: 'data:audio/wav;base64,',
  check: 'data:audio/wav;base64,',
  win: 'data:audio/wav;base64,',
  lose: 'data:audio/wav;base64,',
  urgent: 'data:audio/wav;base64,',
}

let audioContext = null

function getAudioContext() {
  if (!audioContext) {
    audioContext = wx.createInnerAudioContext()
  }
  return audioContext
}

/**
 * 播放音效
 * @param {string} name - move | capture | check | win | lose | urgent
 */
function playSound(name) {
  if (!SOUNDS[name]) return
  try {
    const audio = wx.createInnerAudioContext()
    audio.src = SOUNDS[name]
    audio.volume = 0.6
    audio.play()
    // 播放完后自动销毁
    audio.onEnded(() => { audio.destroy() })
    audio.onError(() => { audio.destroy() })
  } catch (e) {
    // 静默失败
  }
}

module.exports = { playSound, SOUNDS }